import type { RewardsAccountSettingsDocument } from '../models';
import { rewardsAccountSettingsRepository } from '../repository';

export class RewardsAccountSettingsService {
  private readonly repository = rewardsAccountSettingsRepository;

  async checkHasRedeemedCashback(accountId: string): Promise<boolean> {
    const result = await this.repository.consultAccountSettings({ accountNumber: accountId });
    const redeemedAt = result?.invoiceCashbackRedemption?.redeemedAtDate;
    return Boolean(redeemedAt);
  }

  async markCashbackAsRedeemed(accountId: string): Promise<void> {
    const document: RewardsAccountSettingsDocument = {
      codigoCliente: accountId,
      status: 1,
      value: {
        invoiceCashbackRedemption: {
          redeemedAtDate: new Date().toISOString(),
        },
      },
    };
    await this.repository.upsertAccountSettings(document);
  }
}

export const rewardsAccountSettingsService = new RewardsAccountSettingsService();

