describe('RewardsAccountSettingsService', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('checkHasRedeemedCashback', () => {
    it('should return true if redeemedAtDate is present', async () => {
      (rewardsAccountSettingsRepository.consultAccountSettings as jest.Mock).mockResolvedValue({
        invoiceCashbackRedemption: {
          redeemedAtDate: '2023-10-27T10:00:00Z',
        },
      });

      const result = await rewardsAccountSettingsService.checkHasRedeemedCashback('123');
      expect(result).toBe(true);
    });

