import { act, renderHook } from '@testing-library/react-hooks';
import { useSelector } from 'react-redux';
import { rewardsAccountSettingsService } from '../services';
import { useRewardsAccountSettings } from './useRewardsAccountSettings';
import { useRewardsAccountSettingsStore } from './useRewardsAccountSettingsStore';

jest.mock('../services');
jest.mock('react-redux');
jest.mock('./useRewardsAccountSettingsStore');

const mockSetHasRedeemedCashback = jest.fn();
const mockSetLoading = jest.fn();
const mockSetError = jest.fn();

describe('useRewardsAccountSettings', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    (useSelector as jest.Mock).mockReturnValue('123');
    (useRewardsAccountSettingsStore as unknown as jest.Mock).mockImplementation((selector) => {
      if (selector.toString().includes('rewardsAccountSettingsActions')) {
        return {
          setHasRedeemedCashback: mockSetHasRedeemedCashback,
          setLoading: mockSetLoading,
          setError: mockSetError,
        };
      }
      return {
        hasRedeemedCashback: null,
        isLoading: false,
        isError: false,
      };
    });
  });

  describe('checkHasRedeemed', () => {
    it('should call service and update store on success', async () => {
      (rewardsAccountSettingsService.checkHasRedeemedCashback as jest.Mock).mockResolvedValue(true);

      const { result } = renderHook(() => useRewardsAccountSettings());

      await act(async () => {
        const hasRedeemed = await result.current.checkHasRedeemed({ showLoading: true });
        expect(hasRedeemed).toBe(true);
      });

      expect(mockSetLoading).toHaveBeenCalledWith(true);
      expect(rewardsAccountSettingsService.checkHasRedeemedCashback).toHaveBeenCalledWith('123');
      expect(mockSetHasRedeemedCashback).toHaveBeenCalledWith(true);
    });

    it('should handle error', async () => {
      (rewardsAccountSettingsService.checkHasRedeemedCashback as jest.Mock).mockRejectedValue(
        new Error('error')
      );

      const { result } = renderHook(() => useRewardsAccountSettings());

      await act(async () => {
        const hasRedeemed = await result.current.checkHasRedeemed({ showLoading: true });
        expect(hasRedeemed).toBe(false);
      });

      expect(mockSetLoading).toHaveBeenCalledWith(true);
      expect(mockSetError).toHaveBeenCalledWith(true);
    });

    it('should return false if no accountId', async () => {
      (useSelector as jest.Mock).mockReturnValue(null);
      const { result } = renderHook(() => useRewardsAccountSettings());

      await act(async () => {
        const hasRedeemed = await result.current.checkHasRedeemed();
        expect(hasRedeemed).toBe(false);
      });

      expect(rewardsAccountSettingsService.checkHasRedeemedCashback).not.toHaveBeenCalled();
    });
  });

  describe('markAsRedeemed', () => {
    it('should call service and update store on success', async () => {
      (rewardsAccountSettingsService.markCashbackAsRedeemed as jest.Mock).mockResolvedValue(
        undefined
      );

      const { result } = renderHook(() => useRewardsAccountSettings());

      await act(async () => {
        const success = await result.current.markAsRedeemed();
        expect(success).toBe(true);
      });

      expect(rewardsAccountSettingsService.markCashbackAsRedeemed).toHaveBeenCalledWith('123');
      expect(mockSetHasRedeemedCashback).toHaveBeenCalledWith(true);
    });

    it('should return false on error', async () => {
      (rewardsAccountSettingsService.markCashbackAsRedeemed as jest.Mock).mockRejectedValue(
        new Error('error')
      );

      const { result } = renderHook(() => useRewardsAccountSettings());

      await act(async () => {
        const success = await result.current.markAsRedeemed();
        expect(success).toBe(false);
      });
    });
  });
});

